customCSS:
.ds-stat-icon{
display:none;
}

li.page-item {
    list-style-type: none;
    padding: 8px 16px;
    border: var(--ds-border-width-thin) solid var(--ds-border-color-light);
    border-radius: var(--ds-radius-md);
}

li.page-item.active {
color: var(--color-text-tertiary);
     border: var(--ds-border-width-thin) solid var(--color-text-tertiary);

}

li.page-item.disabled {
color: var(--ds-border-color-light);
     border: var(--ds-border-width-thin) var(--ds-border-color-light);

}

.nav-container{
max-width: 1400px;
}


.ds-stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--ds-space-6);
    margin-bottom: var(--ds-space-8);
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: var(--space-md);
    margin-top: var(--space-lg);
}
